arguments.argument:
event_inherited() enemyCount=-1 fadeColor=c_white fadeAlpha=1
global.optShowHUD=0
extCheatFlag=string_char_at(global.extraFlags,10) if extCheatFlag="1" //If player force quit the game in the cheat room after Esc is disabled { fadeColor=make_color_rgb(255,160,160) sceneProgress=100 }
preAchCheck=string_char_at(global.tokenRecognitionsSetTwo,1) if preAchCheck="1" //If player has achievement for cheating { fadeColor=make_color_rgb(200,200,255) sceneProgress=200 }
